<?php
namespace App\Http\Controllers\CommandCenter\Customers; use App\Http\Controllers\Controller; use App\Http\Requests\Customers\CustomerSettingsRequest; use App\Models\Customers\CustomerSetting; use App\Repositories\Customers\CustomerGroupRepository; use App\Services\AuditLogger; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class CustomerSettingsController extends Controller { public function index(Request $r,CustomerGroupRepository $groups):View{return view('command-center.customers.settings',['settings'=>CustomerSetting::firstOrCreate(['company_id'=>$r->user()->company_id]),'groups'=>$groups->options($r->user()->company_id)]);} public function update(CustomerSettingsRequest $r,AuditLogger $audit):RedirectResponse{$settings=CustomerSetting::firstOrCreate(['company_id'=>$r->user()->company_id]);$settings->update($r->validated());$audit->record('customer.settings.updated',$settings,'Customer settings updated');return back()->with('status','Customer settings updated.');} }
